'use client';
import { useState, useEffect } from 'react';
import { COMPANIES } from '@/lib/companies';
import { computeCCID } from '@/lib/permissions';

const LOGO_B64 = '';

function useDebounce(v, d = 350) {
  const [dv, setDv] = useState(v);
  useEffect(() => { const t = setTimeout(() => setDv(v), d); return () => clearTimeout(t); }, [v, d]);
  return dv;
}

// Correct Indian currency for all sizes
function formatIndianCurrency(amount) {
  const n = Number(amount);
  if (isNaN(n)) return '0.00';
  return n.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function Autocomplete({ value, onChange, onSelect, fetchFn, placeholder, maxLength }) {
  const [results, setResults] = useState([]);
  const [show, setShow] = useState(false);
  const debounced = useDebounce(value);
  useEffect(() => {
    if (debounced.length < 1) { setResults([]); return; }
    fetchFn(debounced).then(r => { setResults(r); setShow(true); });
  }, [debounced]);
  return (
    <div className="autocomplete-wrap">
      <input value={value} onChange={e => onChange(e.target.value)}
        onFocus={() => value && setShow(true)} onBlur={() => setTimeout(() => setShow(false), 150)}
        placeholder={placeholder} maxLength={maxLength} />
      {show && results.length > 0 && (
        <div className="autocomplete-list">
          {results.map((r, i) => (
            <div key={i} className="autocomplete-item" onMouseDown={() => { onSelect(r); setShow(false); }}>
              {typeof r === 'string' ? r : r.Name}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// Warn (don't block) if the typed product name isn't in the Products table
function ProductWarning({ name }) {
  const [known, setKnown] = useState(true);
  const debounced = useDebounce(name, 600);
  useEffect(() => {
    if (!debounced.trim()) { setKnown(true); return; }
    fetch(`/api/products?q=${encodeURIComponent(debounced)}`)
      .then(r => r.json())
      .then(list => {
        const exact = list.some(p => p.toLowerCase() === debounced.toLowerCase());
        setKnown(exact);
      })
      .catch(() => setKnown(true)); // don't warn on network error
  }, [debounced]);
  if (!name.trim() || known) return null;
  return (
    <span title="This product isn't in the Products database — it will still appear on the challan"
      style={{ fontSize:10, color:'var(--warn)', display:'block', marginTop:2 }}>
      ⚠ Not in product list (will still work)
    </span>
  );
}

const emptyProduct = () => ({ name: '', ln_code: '', price: '', quantity: 1 });

const STATUS_META = {
  awaiting_delivery: { label: 'Awaiting Delivery', cls: 'badge-committed' },
  rtc:               { label: 'Released to Customer', cls: 'badge-confirmed' },
  cancelled:         { label: 'Cancelled', cls: 'badge-cancelled' },
};

function isStale(row) {
  if (row.status !== 'awaiting_delivery') return false;
  const raw = row['Generated DateTime'] || '';
  const parts = raw.split(' ')[0]?.split('-');
  if (!parts || parts.length < 3) return false;
  const d = new Date(parts[2], parts[1] - 1, parts[0]);
  return (Date.now() - d.getTime()) >= 3 * 24 * 60 * 60 * 1000;
}

