// ── PDF Generation ────────────────────────────────────────────────────────────
// returnBlob=true → returns base64 string for email attachment instead of saving
async function generatePDF(challan, returnBlob = false) {
  const { default: jsPDF } = await import('jspdf');
  const doc = new jsPDF({ unit: 'pt', format: 'a4' });
  const W = 595.28, H = 841.89, margin = 35;

  // Logo
  const logoDataUrl = 'data:image/png;base64,' + LOGO_B64;
  const logoMaxH = 80, logoMaxW = W - 2 * margin;
  const imgDims = await new Promise(resolve => {
    const img = new Image();
    img.onload = () => resolve({ w: img.naturalWidth, h: img.naturalHeight });
    img.onerror = () => resolve({ w: 1, h: 1 });
    img.src = logoDataUrl;
  });
  const scale = Math.min(logoMaxW / imgDims.w, logoMaxH / imgDims.h, 1);
  const logoW = imgDims.w * scale, logoH = imgDims.h * scale;
  doc.addImage(logoDataUrl, 'PNG', margin + (logoMaxW - logoW) / 2, margin, logoW, logoH);

  // Outer border
  doc.setDrawColor(0).setLineWidth(0.75);
  doc.rect(margin, margin + 90, W - 2 * margin, (H - 2 * margin) - 95);

  // Title
  const outerBoxTop = margin + 90;
  doc.setFontSize(14).setFont('helvetica', 'bold');
  doc.text('DELIVERY CHALLAN', W / 2, outerBoxTop + 28, { align: 'center' });

  // Header boxes
  const headerTop = outerBoxTop + 50, headerHeight = 70, halfW = (W - 2 * margin) / 2;
  doc.rect(margin, headerTop, halfW, headerHeight);
  doc.rect(margin + halfW, headerTop, halfW, headerHeight);

  // Helper: first line only, clipped to maxW
  function clipLine(text, maxW) {
    return doc.splitTextToSize(String(text || ''), maxW)[0] || '';
  }

  // Left: company info
  const cx = margin + 10, cy = headerTop + 10;
  doc.setFontSize(12).setFont('helvetica', 'bold');
  doc.text(challan.company.name, cx, cy + 5);
  doc.setFontSize(9).setFont('helvetica', 'normal');
  doc.text(clipLine(challan.company.address, halfW - 20), cx, cy + 20);
  doc.text(challan.company.gstin, cx, cy + 35);
  doc.text(challan.company.phone, cx, cy + 50);

  // Right: challan info — all clipped to column width
  const rx = margin + halfW + 10, ry = headerTop + 10, rw = halfW - 15;
  doc.setFontSize(9).setFont('helvetica', 'normal');
  doc.text(clipLine('Challan No: '    + challan.challanNumber,            rw), rx, ry + 5);
  doc.text(clipLine('Challan Date: '  + challan.challanDate,              rw), rx, ry + 20);
  doc.text(clipLine('Invoice No: '    + (challan.invoiceReference || ''), rw), rx, ry + 35);
  doc.text(clipLine('Invoice Dated: ' + (challan.invoiceDated || ''),     rw), rx, ry + 50);

  // Buyer box
  const buyerTop = headerTop + headerHeight, buyerHeight = 90;
  doc.line(margin + halfW, buyerTop, margin + halfW, buyerTop + buyerHeight);

  const bx = margin + 10, by = buyerTop + 15, bw = halfW - 35; // tighter to prevent overflow into right column
  // Ship To: wraps to max 2 lines (matches Address behaviour)
  const custName = (challan.customer.name || '').substring(0, 55);
  const shipToLines = doc.splitTextToSize('Ship To: ' + custName, bw).slice(0, 2);
  doc.setFontSize(10).setFont('helvetica', 'bold');
  doc.text(shipToLines, bx, by);

  // Track Y position dynamically so nothing overlaps
  const lh10 = 13; // line-height for 10pt bold
  const lh9  = 12; // line-height for 9pt normal
  let lineY = by + shipToLines.length * lh10 + 2;

  doc.setFontSize(9).setFont('helvetica', 'normal');
  doc.text(clipLine('Mobile: ' + (challan.customer.mobile || ''), bw), bx, lineY);
  lineY += lh9;
  doc.text(clipLine('GSTIN: '  + (challan.customer.gstin  || ''), bw), bx, lineY);
  lineY += lh9;
  const addrLines = doc.splitTextToSize(
    'Address: ' + (challan.customer.address1 || '') + ' ' + (challan.customer.address2 || ''), bw
  ).slice(0, 2);
  doc.text(addrLines, bx, lineY);

  // Right side of buyer box — clipped
  const ox = margin + halfW + 10, oy = buyerTop + 15, ow = halfW - 15;
  doc.setFontSize(9).setFont('helvetica', 'normal');
  doc.text(clipLine('Order No: '    + (challan.orderReference || ''), ow), ox, oy);
  doc.text(clipLine('Order Dated: ' + (challan.orderDate      || ''), ow), ox, oy + 15);
  if (challan.ccid) doc.text(clipLine('CCID: ' + challan.ccid, ow), ox, oy + 30);

  // Product table
  const tableTop  = buyerTop + buyerHeight;
  const tableLeft = margin + 10, tableWidth = W - 2 * margin - 20;
  const colWidths = [50, 300, 70, tableWidth - 420];
  const signBoxHeight = 90, signY = H - margin - signBoxHeight;
  const productBoxH = (signY - 5) - tableTop;
  const noteAreaH = 28, colLinesEnd = tableTop + productBoxH - noteAreaH;

  doc.rect(margin, tableTop, tableWidth + 20, productBoxH);

  let colX = tableLeft;
  for (let i = 0; i < colWidths.length - 1; i++) {
    colX += colWidths[i];
    doc.line(colX, tableTop, colX, colLinesEnd);
  }
  doc.line(margin, colLinesEnd, margin + tableWidth + 20, colLinesEnd);

  doc.rect(margin, tableTop, tableWidth + 20, 30, 'S');
  doc.setFontSize(12).setFont('helvetica', 'bold');
  doc.text('Sr. No',     tableLeft + 2,                                              tableTop + 20);
  doc.text('Description',tableLeft + colWidths[0] + 100,                             tableTop + 20);
  doc.text('Qty',        tableLeft + colWidths[0] + colWidths[1] + 15,               tableTop + 20);
  doc.text('Unit Price', tableLeft + colWidths[0] + colWidths[1] + colWidths[2] + 8, tableTop + 20);

  // Product rows — dynamic height per row
  let rowY = tableTop + 40;
  const lineH = 14;
  for (let i = 0; i < challan.products.length; i++) {
    const p = challan.products[i];
    const descLines = doc.splitTextToSize('Godrej ' + p.name, colWidths[1] - 16);
    const rowH = Math.max(30, descLines.length * lineH + 8);
    if (rowY + rowH > colLinesEnd - 5) break; // stop before note area
    doc.setFontSize(12).setFont('helvetica', 'bold');
    doc.text((i + 1) + '.', tableLeft + 8, rowY + 12);
    doc.text(descLines, tableLeft + colWidths[0] + 8, rowY + 12);
    doc.text(String(p.quantity), tableLeft + colWidths[0] + colWidths[1] + 30, rowY + 12);
    doc.text(formatIndianCurrency(parseFloat(p.price) || 0),
      tableLeft + colWidths[0] + colWidths[1] + colWidths[2] + 20, rowY + 12);
    rowY += rowH;
  }

  // E. & O.E.
  const noteTop = colLinesEnd;
  doc.setFontSize(9).setFont('helvetica', 'normal');
  doc.text('E. & O.E.', W / 2, noteTop + 11, { align: 'center' });
  doc.text('All the listed items have been received in order and good condition.', W / 2, noteTop + 21, { align: 'center' });

  // Signature boxes
  const totalW = W - 2 * margin, sigW = totalW / 3;
  for (let i = 0; i < 3; i++) doc.rect(margin + i * sigW, signY - 5, sigW, signBoxHeight);
  doc.setFontSize(12).setFont('helvetica', 'bold');
  doc.text('Received in Good Condition', margin + 5, signY + 10);
  doc.setFontSize(9).setFont('helvetica', 'normal');
  doc.text('Recipient Signature', margin + 5, signY + 75);
  doc.setFontSize(12).setFont('helvetica', 'bold');
  doc.text('For ' + challan.company.name, margin + sigW + 10, signY + 10);
  doc.setFontSize(9).setFont('helvetica', 'normal');
  doc.text('Authorised Signatory', margin + sigW + 10, signY + 75);
  doc.setFontSize(12).setFont('helvetica', 'bold');
  doc.text('Goods Transporter', margin + 2 * sigW + 10, signY + 10);
  doc.setFontSize(9).setFont('helvetica', 'normal');
  doc.text('Signature', margin + 2 * sigW + 10, signY + 75);

  if (returnBlob) {
    return doc.output('datauristring').split(',')[1]; // base64 string
  }
  doc.save(challan.challanNumber.replace(/\//g, '-') + '.pdf');
}

// ── Reprint helpers ──────────────────────────────────────────────────────────

// Parse "ProductName (Rs.1,000.00 x 2); ..." back into product objects
function parseProductsString(str) {
  if (!str) return [];
  return str.split('; ').map(item => {
    const match = item.match(/^(.+?)\s+\(Rs\.([\d,]+\.?\d*)\s+x\s+(\d+)\)$/);
    if (match) {
      return {
        name:     match[1],
        price:    parseFloat(match[2].replace(/,/g, '')),
        quantity: parseInt(match[3]),
      };
    }
    // Fallback: no price/qty info found
    return { name: item.replace(/\s+\(Rs\..*$/, ''), price: 0, quantity: 1 };
  }).filter(p => p.name.trim());
}

// Reconstruct challan data from a ChallanRecords row and regenerate the PDF
async function reprintChallan(row) {
  const prefix     = (row['Challan Number'] || '').split('/')[0];
  const prefixMap  = { SCC: 'soma', NCC: 'nalanda', GEC: 'gangotri' };
  const company    = COMPANIES[prefixMap[prefix]] || Object.values(COMPANIES)[0];

  // Reconstruct challan date from Generated DateTime ("DD-MM-YYYY HH:MM")
  let challanDate = row['Order Dated'] || '';
  const genDT = row['Generated DateTime'] || '';
  if (genDT) {
    const parts = genDT.split(' ')[0]?.split('-');
    if (parts?.length === 3) {
      const d = new Date(parts[2], parts[1] - 1, parts[0]);
      if (!isNaN(d)) {
        challanDate = d.toLocaleDateString('en-IN', {
          day: '2-digit', month: 'short', year: 'numeric'
        }).replace(/ /g, '-');
      }
    }
  }

  const challanData = {
    challanNumber:    row['Challan Number'],
    challanDate,
    ccid:             row.ccid || '',
    company,
    customer: {
      name:     row['Customer Name']  || '',
      gstin:    row['GSTIN']          || '',
      address1: row['Address Line 1'] || '',
      address2: row['Address Line 2'] || '',
      mobile:   row['Mobile']         || '',
    },
    products:         parseProductsString(row['Products']),
    orderReference:   row['Order Reference']  || '',
    orderDate:        row['Order Dated']       || '',
    invoiceReference: row.invoice_reference   || '',
    invoiceDated:     row.invoice_dated        || '',
  };

  await generatePDF(challanData);
}

// ── Records Table ─────────────────────────────────────────────────────────────
function RecordsTable({ rows, user, onAction, loading }) {
  if (loading) return <div className="spinner" style={{ margin: '20px auto' }} />;
  if (!rows.length) return <p style={{ color: 'var(--muted)', padding: 12 }}>No challans found.</p>;
  const perms = user?.permissions || {};
  return (
    <div style={{ overflowX: 'auto' }}>
      <table>
        <thead>
          <tr>
            <th>Challan No.</th><th>CCID</th><th>Customer</th>
            <th>Date</th><th>Status</th><th>Invoice No.</th><th>By</th><th>Actions</th><th>PDF</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((row, i) => {
            const stale = isStale(row);
            const meta  = STATUS_META[row.status] || STATUS_META.awaiting_delivery;
            const cn    = row['Challan Number'];
            return (
              <tr key={i} style={{ background: stale ? '#fff8e1' : undefined }}>
                <td className="mono" style={{ fontSize: 11, whiteSpace: 'nowrap' }}>
                  {stale && <span title="3+ days awaiting delivery" style={{ marginRight: 4 }}>⚠️</span>}
                  {cn}
                </td>
                <td className="mono" style={{ fontSize: 10, color: 'var(--muted)' }}>{row.ccid || '—'}</td>
                <td style={{ fontSize: 12 }}>{row['Customer Name']}</td>
                <td style={{ fontSize: 11, color: 'var(--muted)', whiteSpace: 'nowrap' }}>{row['Order Dated']}</td>
                <td><span className={`badge ${meta.cls}`}>{meta.label}</span></td>
                <td style={{ fontSize: 11 }}>{row.invoice_reference || <span style={{ color: 'var(--muted)' }}>—</span>}</td>
                <td style={{ fontSize: 11, color: 'var(--muted)' }}>{row.created_by_name || '—'}</td>
                <td style={{ whiteSpace: 'nowrap' }}>
                  {row.status === 'awaiting_delivery' && perms.rtc_challan && (
                    <button className="btn btn-primary btn-sm" style={{ marginRight: 4 }} onClick={() => onAction(cn, 'rtc')}>RTC</button>
                  )}
                  {row.status !== 'cancelled' && row.status !== 'rtc' && perms.cancel_challan && (
                    <button className="btn btn-danger btn-sm" onClick={() => onAction(cn, 'cancel')}>Cancel</button>
                  )}
                  {!perms.rtc_challan && !perms.cancel_challan && <span style={{ fontSize: 11, color: 'var(--muted)' }}>—</span>}
                </td>
                <td>
                  <button className="btn btn-secondary btn-sm" onClick={() => reprintChallan(row)}
                    title={`Reprint ${cn}`}>
                    ⬇ PDF
                  </button>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

// ── Unbilled Table ────────────────────────────────────────────────────────────
function UnbilledTable({ rows, onAddInvoice, loading }) {
  const [inputs, setInputs] = useState({});
  const [saving, setSaving] = useState({});
  if (loading) return <div className="spinner" style={{ margin: '20px auto' }} />;
  if (!rows.length) return <div className="alert alert-success" style={{ marginTop: 12 }}>✓ All challans have invoice numbers.</div>;
  async function submit(challanNo) {
    const val = inputs[challanNo]?.trim();
    if (!val) return;
    setSaving(p => ({ ...p, [challanNo]: true }));
    await onAddInvoice(challanNo, val);
    setSaving(p => ({ ...p, [challanNo]: false }));
  }
  return (
    <div style={{ overflowX: 'auto' }}>
      <div className="alert alert-info" style={{ marginBottom: 12 }}>
        These challans were supplied without an invoice. Add the invoice number once billed.
      </div>
      <table>
        <thead>
          <tr><th>Challan No.</th><th>Customer</th><th>Date</th><th>Status</th><th>CCID</th><th>Add Invoice No.</th></tr>
        </thead>
        <tbody>
          {rows.map((row, i) => {
            const cn   = row['Challan Number'];
            const meta = STATUS_META[row.status] || STATUS_META.awaiting_delivery;
            return (
              <tr key={i}>
                <td className="mono" style={{ fontSize: 11 }}>{cn}</td>
                <td style={{ fontSize: 12 }}>{row['Customer Name']}</td>
                <td style={{ fontSize: 11, color: 'var(--muted)' }}>{row['Order Dated']}</td>
                <td><span className={`badge ${meta.cls}`}>{meta.label}</span></td>
                <td className="mono" style={{ fontSize: 10, color: 'var(--muted)' }}>{row.ccid || '—'}</td>
                <td>
                  <div style={{ display: 'flex', gap: 6 }}>
                    <input value={inputs[cn] || ''} onChange={e => setInputs(p => ({ ...p, [cn]: e.target.value }))}
                      placeholder="INV/2026/001" maxLength={20} style={{ width: 140 }}
                      onKeyDown={e => e.key === 'Enter' && submit(cn)} />
                    <button className="btn btn-primary btn-sm" disabled={saving[cn]} onClick={() => submit(cn)}>
                      {saving[cn] ? '…' : 'Save'}
                    </button>
                  </div>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

// ── Recent Mini Sidebar ───────────────────────────────────────────────────────
function RecentMini() {
  const [rows, setRows]       = useState([]);
  const [loading, setLoading] = useState(true);
  const [err, setErr]         = useState('');
  useEffect(() => {
    fetch('/api/challan?limit=20')
      .then(r => { if (!r.ok) throw new Error(`HTTP ${r.status}`); return r.json(); })
      .then(d => { setRows(d.data || []); setLoading(false); })
      .catch(e => { setErr(e.message); setLoading(false); });
  }, []);
  if (err)     return <p style={{ fontSize: 11, color: 'var(--danger)' }}>Error: {err}</p>;
  if (loading) return <div className="spinner" />;
  return (
    <div style={{ maxHeight: 'calc(100vh - 200px)', overflowY: 'auto' }}>
      <table>
        <thead><tr><th>Challan</th><th>Customer</th><th>Status</th></tr></thead>
        <tbody>
          {rows.length === 0 && <tr><td colSpan={3} style={{ color: 'var(--muted)', textAlign: 'center' }}>None yet</td></tr>}
          {rows.map((row, i) => {
            const meta = STATUS_META[row.status] || STATUS_META.awaiting_delivery;
            return (
              <tr key={i} style={{ background: isStale(row) ? '#fff8e1' : undefined }}>
                <td className="mono" style={{ fontSize: 10 }}>{row['Challan Number']}</td>
                <td style={{ fontSize: 11 }}>{row['Customer Name']}</td>
                <td><span className={`badge ${meta.cls}`} style={{ fontSize: 9 }}>{meta.label.split(' ')[0]}</span></td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

// ── Main Page ─────────────────────────────────────────────────────────────────
export default function ChallanPage() {
  const [user,             setUser]             = useState(null);
  const [activeTab,        setActiveTab]        = useState('new');
  const [loading,          setLoading]          = useState(false);
  const [error,            setError]            = useState('');
  const [success,          setSuccess]          = useState('');
  const [generatedChallan, setGeneratedChallan] = useState(null);
  const [showInternal,     setShowInternal]     = useState(false);
  const [emailStatus,      setEmailStatus]      = useState(''); // 'sending'|'sent'|'failed:...'|''
  const [records,          setRecords]          = useState([]);
  const [recordsCount,     setRecordsCount]     = useState(0);
  const [recLoading,       setRecLoading]       = useState(false);
  const [recSearch,        setRecSearch]        = useState('');
  const [recStatus,        setRecStatus]        = useState('');
  const [recMonth,         setRecMonth]         = useState('');
  const [recYear,          setRecYear]          = useState(String(new Date().getFullYear()));
  const [unbilled,         setUnbilled]         = useState([]);
  const [unbilledLoad,     setUnbilledLoad]     = useState(false);
  const [companyId,        setCompanyId]        = useState('');
  const [previewNumber,    setPreviewNumber]    = useState('');
  const [customerName,     setCustomerName]     = useState('');
  const [customerGstin,    setCustomerGstin]    = useState('');
  const [customerAddr1,    setCustomerAddr1]    = useState('');
  const [customerAddr2,    setCustomerAddr2]    = useState('');
  const [customerMobile,   setCustomerMobile]   = useState('');
  const [saveCustomer,     setSaveCustomer]     = useState(false);
  const [orderRef,         setOrderRef]         = useState('');
  const [orderDate,        setOrderDate]        = useState(new Date().toISOString().split('T')[0]);
  const [invoiceRef,       setInvoiceRef]       = useState('');
  const [invoiceDate,      setInvoiceDate]      = useState('');
  const [products,         setProducts]         = useState([emptyProduct()]);
  const debRecSearch = useDebounce(recSearch, 400);

  useEffect(() => {
    fetch('/api/auth/me').then(r => r.json()).then(u => { setUser(u); setCompanyId(u.company); });
  }, []);

  useEffect(() => {
    if (!companyId || activeTab !== 'new') return;
    setPreviewNumber('loading');
    fetch(`/api/challan/preview?company=${companyId}`)
      .then(r => { if (!r.ok) throw new Error(r.status); return r.json(); })
      .then(d => setPreviewNumber(d.preview || '?'))
      .catch(() => setPreviewNumber('?'));
  }, [companyId, activeTab]);

  useEffect(() => { if (activeTab === 'records') loadRecords(); }, [activeTab, debRecSearch, recStatus, recMonth, recYear, showInternal]);
  useEffect(() => { if (activeTab === 'unbilled') loadUnbilled(); }, [activeTab]);

  async function loadRecords() {
    setRecLoading(true);
    const params = new URLSearchParams({ limit: '200' });
    if (debRecSearch)  params.set('search', debRecSearch);
    if (recStatus)     params.set('status', recStatus);
    if (recMonth)      params.set('month',  recMonth);
    if (recYear)       params.set('year',   recYear);
    if (!showInternal) params.set('exclude_internal', '1');
    const res = await fetch(`/api/challan?${params}`);
    const { data, count } = await res.json();
    setRecords(data || []); setRecordsCount(count || 0); setRecLoading(false);
  }

  async function loadUnbilled() {
    setUnbilledLoad(true);
    const res = await fetch('/api/challan?unbilled=1&limit=200');
    const { data } = await res.json();
    setUnbilled(data || []); setUnbilledLoad(false);
  }

  async function handleLifecycleAction(challanNumber, action) {
    const label = action === 'rtc' ? 'Release to Customer' : 'Cancel';
    if (!confirm(`${label} challan ${challanNumber}?`)) return;
    const res = await fetch('/api/challan/lifecycle', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ challanNumber, action }),
    });
    if (res.ok) { setSuccess(`Challan ${action === 'rtc' ? 'released' : 'cancelled'}.`); loadRecords(); }
    else { const d = await res.json(); setError(d.error); }
  }

  async function handleAddInvoice(challanNumber, invoiceReference) {
    const res = await fetch('/api/challan/lifecycle', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ challanNumber, action: 'add_invoice', invoiceReference }),
    });
    if (res.ok) { setSuccess('Invoice number saved.'); loadUnbilled(); }
    else { const d = await res.json(); setError(d.error); }
  }

  function fillCustomer(c) {
    setCustomerName(c.Name || ''); setCustomerGstin(c.GSTIN || '');
    setCustomerAddr1(c.Address_L1 || ''); setCustomerAddr2(c.Address_L2 || '');
    setCustomerMobile(c.Number || '');
  }
  function setProductField(i, field, val) {
    setProducts(prev => prev.map((p, idx) => idx === i ? { ...p, [field]: val } : p));
  }

  async function onProductSelect(i, nameVal) {
    setProductField(i, 'name', nameVal);
    try {
      const res  = await fetch(`/api/products?q=${encodeURIComponent(nameVal)}&limit=1`);
      const list = await res.json();
      const match = Array.isArray(list) && list.find(p => p.name?.toLowerCase() === nameVal.toLowerCase());
      if (match?.ln_code) {
        setProducts(prev => prev.map((p, idx) => idx !== i ? p : {
          ...p,
          name:    match.name,
          ln_code: match.ln_code,
          price:   p.price || (match.base_price ? String(match.base_price) : p.price),
        }));
      }
    } catch { /* ignore */ }
  }

  async function onLNCodeChange(i, lnVal) {
    const upper = lnVal.toUpperCase();
    setProductField(i, 'ln_code', upper);
    if (upper.length === 15) {
      try {
        const res     = await fetch(`/api/products?ln=${encodeURIComponent(upper)}`);
        const product = await res.json();
        if (product?.name) {
          setProducts(prev => prev.map((p, idx) => idx !== i ? p : {
            ...p,
            ln_code: product.ln_code,
            name:    p.name || product.name,
            price:   p.price || (product.base_price ? String(product.base_price) : p.price),
          }));
        }
      } catch { /* ignore */ }
    }
  }
  const total = products.reduce((s, p) => s + (parseFloat(p.price)||0)*(parseInt(p.quantity)||0), 0);

  async function handleGenerate(e) {
    e.preventDefault();
    setError(''); setSuccess('');
    if (!customerName.trim()) { setError('Customer name is required.'); return; }
    const valid = products.filter(p => p.name.trim() && parseFloat(p.price) > 0).slice(0, 10);
    if (!valid.length) { setError('At least one product with name and price is required.'); return; }
    setLoading(true);
    try {
      const res = await fetch('/api/challan', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          companyOverride: companyId, orderReference: orderRef, orderDate,
          invoiceReference: invoiceRef, invoiceDated: invoiceDate,
          customer: { name: customerName, gstin: customerGstin, address1: customerAddr1, address2: customerAddr2, mobile: customerMobile, save: saveCustomer },
          products: valid,
        }),
      });
      const data = await res.json();
      if (!res.ok) { setError(data.error); return; }
      setGeneratedChallan(data);
      setSuccess(`Challan ${data.challanNumber} generated. Preparing email…`);
      // Auto-send email with PDF attachment (matches C# implementation)
      setEmailStatus('sending');
      try {
        const pdfBase64 = await generatePDF(data, true); // generate but return base64
        const pdfFilename = data.challanNumber.replace(/\//g, '-') + '.pdf';
        const emailRes = await fetch('/api/email', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            to:          data.company.defaultEmail,
            toName:      data.company.name,
            subject:     `Delivery Challan ${data.challanNumber} — ${data.customer.name}`,
            htmlBody:    buildChallanEmailHTML(data),
            pdfBase64,
            pdfFilename,
          }),
        });
        const emailData = await emailRes.json();
        if (emailRes.ok) {
          setEmailStatus('sent');
          setSuccess(`Challan ${data.challanNumber} generated. ✓ Email sent to ${data.company.defaultEmail}.`);
        } else {
          setEmailStatus('failed');
          setSuccess(`Challan ${data.challanNumber} generated.`);
          setError(`Email failed: ${emailData.error}${emailData.hint ? ' — ' + emailData.hint : ''}`);
        }
      } catch (emailErr) {
        setEmailStatus('failed');
        setSuccess(`Challan ${data.challanNumber} generated.`);
        setError(`Email error: ${emailErr.message}`);
      }

      fetch(`/api/challan/preview?company=${companyId}`).then(r => r.json()).then(d => setPreviewNumber(d.preview || ''));
    } catch (err) { setError(err.message); }
    finally { setLoading(false); }
  }


  function resetForm() {
    setCustomerName(''); setCustomerGstin(''); setCustomerAddr1(''); setCustomerAddr2('');
    setCustomerMobile(''); setOrderRef(''); setOrderDate(new Date().toISOString().split('T')[0]);
    setInvoiceRef(''); setInvoiceDate(''); setProducts([emptyProduct()]);
    setSaveCustomer(false); setGeneratedChallan(null); setError(''); setSuccess(''); setEmailStatus('');
  }

  const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const currentYear = new Date().getFullYear();
  const years = [currentYear - 1, currentYear, currentYear + 1];

  return (
    <div className="page">
      {error   && <div className="alert alert-error"   style={{ marginBottom: 12 }}>{error}<button onClick={() => setError('')}   style={{ float:'right', background:'none', border:'none', cursor:'pointer' }}>×</button></div>}
      {success && <div className="alert alert-success" style={{ marginBottom: 12 }}>{success}<button onClick={() => setSuccess('')} style={{ float:'right', background:'none', border:'none', cursor:'pointer' }}>×</button></div>}

      {/* Tabs */}
      <div style={{ display:'flex', gap:2, marginBottom:20, borderBottom:'2px solid var(--border)', paddingBottom:0 }}>
        {[['new','New Challan'],['records','All Records'],['unbilled','Unbilled']].map(([key,label]) => (
          <button key={key} onClick={() => setActiveTab(key)}
            style={{ padding:'7px 18px', fontFamily:'var(--font)', fontSize:13, fontWeight: activeTab===key ? 700 : 400,
              background:'none', border:'none', cursor:'pointer',
              borderBottom: activeTab===key ? '2px solid var(--accent)' : '2px solid transparent',
              color: activeTab===key ? 'var(--accent)' : 'var(--muted)', marginBottom:-2 }}>
            {label}
            {key==='unbilled' && unbilled.length>0 && (
              <span style={{ marginLeft:6, background:'var(--warn)', color:'#fff', borderRadius:10, padding:'1px 6px', fontSize:11 }}>{unbilled.length}</span>
            )}
          </button>
        ))}
      </div>

      {/* ── NEW CHALLAN ── */}
      {activeTab === 'new' && (
        <div style={{ display:'grid', gridTemplateColumns:'1fr 340px', gap:20, alignItems:'start' }}>
          <div>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>
              <h2 className="page-title" style={{ margin:0 }}>New Challan</h2>
              <div style={{ display:'flex', alignItems:'center', gap:12 }}>
                <span title="Estimated next number — not reserved"
                  style={{ fontFamily:'var(--font-mono)', fontSize:13, color:'var(--muted)', background:'#f0f0ec', padding:'3px 10px', border:'1px solid var(--border)', minWidth:160, display:'inline-block' }}>
                  {previewNumber === 'loading' ? 'Next: …'
                    : previewNumber ? <>Next: <strong style={{ color:'var(--text)' }}>{previewNumber}</strong></> : 'Next: —'}
                </span>
                {generatedChallan && <button className="btn btn-secondary btn-sm" onClick={resetForm}>+ New</button>}
              </div>
            </div>

            {generatedChallan ? (
              <div className="card">
                <div style={{ fontSize:20, fontFamily:'var(--font-mono)', fontWeight:700, marginBottom:4 }}>{generatedChallan.challanNumber}</div>
                <div style={{ fontSize:12, color:'var(--muted)', marginBottom:14, fontFamily:'var(--font-mono)' }}>CCID: {generatedChallan.ccid}</div>
                <div style={{ display:'flex', gap:10, flexWrap:'wrap', alignItems:'center' }}>
                  <button className="btn btn-primary" onClick={() => generatePDF(generatedChallan)}>⬇ Download PDF</button>
                  <button className="btn btn-secondary" onClick={resetForm}>+ New Challan</button>
                  <span style={{ fontSize:12, color: emailStatus === 'sent' ? 'var(--success)' : emailStatus === 'sending' ? 'var(--muted)' : emailStatus === 'failed' ? 'var(--danger)' : 'var(--muted)' }}>
                    {emailStatus === 'sending' && '⏳ Sending email…'}
                    {emailStatus === 'sent'    && `✓ Email sent to ${generatedChallan?.company?.defaultEmail}`}
                    {emailStatus === 'failed'  && '✗ Email failed — see error above'}
                  </span>
                </div>
              </div>
            ) : (
              <form onSubmit={handleGenerate}>
                {user?.role === 'owner' && (
                  <div className="card">
                    <div className="card-title">Company</div>
                    <select value={companyId} onChange={e => setCompanyId(e.target.value)} style={{ maxWidth:260 }}>
                      {Object.values(COMPANIES).map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                    </select>
                  </div>
                )}

                <div className="card">
                  <div className="card-title">Customer</div>
                  <div className="form-grid">
                    <div className="form-group span-2">
                      <label>Customer Name *</label>
                      <Autocomplete value={customerName} onChange={setCustomerName} onSelect={fillCustomer} maxLength={55}
                        fetchFn={q => fetch(`/api/customers?q=${encodeURIComponent(q)}`).then(r => r.json())}
                        placeholder="Search or enter name…" />
                    </div>
                    <div className="form-group">
                      <label>GSTIN</label>
                      <input value={customerGstin} onChange={e => setCustomerGstin(e.target.value)} placeholder="09XXXXX…" maxLength={25} />
                    </div>
                    <div className="form-group">
                      <label>Mobile</label>
                      <input value={customerMobile} onChange={e => setCustomerMobile(e.target.value)} maxLength={14} placeholder="9876543210" />
                    </div>
                    <div className="form-group">
                      <label>Address Line 1</label>
                      <input value={customerAddr1} onChange={e => setCustomerAddr1(e.target.value)} maxLength={50} />
                    </div>
                    <div className="form-group">
                      <label>Address Line 2</label>
                      <input value={customerAddr2} onChange={e => setCustomerAddr2(e.target.value)} maxLength={50} />
                    </div>
                    <div className="form-group" style={{ gridColumn:'1/-1' }}>
                      <label style={{ display:'flex', gap:6, alignItems:'center', textTransform:'none', letterSpacing:0 }}>
                        <input type="checkbox" checked={saveCustomer} onChange={e => setSaveCustomer(e.target.checked)} style={{ width:'auto' }} />
                        Save / update customer in database
                      </label>
                    </div>
                  </div>
                </div>

                <div className="card">
                  <div className="card-title">Order &amp; Invoice Details</div>
                  <div className="form-grid">
                    <div className="form-group">
                      <label>Order Reference</label>
                      <input value={orderRef} onChange={e => setOrderRef(e.target.value)} placeholder="SCI/2026-27/001" maxLength={20} />
                    </div>
                    <div className="form-group">
                      <label>Order Date</label>
                      <input type="date" value={orderDate} onChange={e => setOrderDate(e.target.value)} />
                    </div>
                    <div className="form-group">
                      <label>Invoice No <span style={{ color:'var(--muted)', fontWeight:400, textTransform:'none' }}>(blank = unbilled)</span></label>
                      <input value={invoiceRef} onChange={e => setInvoiceRef(e.target.value)} placeholder="INV/2026/001" maxLength={20} />
                    </div>
                    <div className="form-group">
                      <label>Invoice Date</label>
                      <input type="date" value={invoiceDate} onChange={e => setInvoiceDate(e.target.value)} />
                    </div>
                  </div>
                </div>

                <div className="card">
                  <div className="card-title" style={{ display:'flex', justifyContent:'space-between' }}>
                    Products
                    <button type="button" className="btn btn-secondary btn-sm" onClick={() => setProducts(p => [...p, emptyProduct()])} disabled={products.length >= 10} title={products.length >= 10 ? "Maximum 10 items per challan" : ""}>+ Add Row{products.length >= 10 ? " (max)" : ` (${products.length}/10)`}</button>
                  </div>
                  <div style={{ fontSize:11, color:'var(--muted)', marginBottom:8, display:'grid', gridTemplateColumns:'2fr 160px 120px 70px 100px 30px', gap:6 }}>
                    <span>Product Name <em>("Godrej " added automatically)</em></span>
                    <span style={{ color:'var(--accent)' }}>LN Code <em>(optional)</em></span>
                    <span>Price (₹)</span><span>Qty</span><span>Total (₹)</span><span></span>
                  </div>
                  {products.map((p, i) => (
                    <div key={i} className="product-row" style={{ display:"grid", gridTemplateColumns:"2fr 160px 120px 70px 100px 30px", gap:6, alignItems:"start" }}>
                      <div>
                        <Autocomplete value={p.name}
                          onChange={v => setProductField(i,'name',v)}
                          onSelect={v => onProductSelect(i, v)}
                          fetchFn={q => fetch(`/api/products?q=${encodeURIComponent(q)}`).then(r => r.json()).then(list => Array.isArray(list) ? list.map(x => x.name || x) : list)}
                          placeholder="Search product…" maxLength={60} />
                        <ProductWarning name={p.name} />
                      </div>
                      <input
                        value={p.ln_code || ''}
                        onChange={e => onLNCodeChange(i, e.target.value)}
                        placeholder="e.g. 56101509SD00493"
                        maxLength={15}
                        style={{ fontFamily:'var(--font-mono)', fontSize:11,
                          borderColor: p.ln_code?.length === 15 ? 'var(--success)' : undefined }}
                        title="LN Code — auto-fills when product is selected" />
                      <input type="number" min="0" max="9999999" step="0.01" value={p.price}
                        onChange={e => setProductField(i,'price',e.target.value)} placeholder="0.00" />
                      <input type="number" min="1" max="9999" value={p.quantity}
                        onChange={e => setProductField(i,'quantity',e.target.value)} />
                      <input readOnly value={((parseFloat(p.price)||0)*(parseInt(p.quantity)||0)).toLocaleString('en-IN',{ minimumFractionDigits:2 })}
                        style={{ background:'#f5f5f2', color:'var(--muted)' }} />
                      <button type="button" onClick={() => setProducts(prev => prev.filter((_,idx) => idx !== i))}
                        style={{ background:'none', border:'none', cursor:'pointer', color:'var(--danger)', fontSize:16, padding:0 }}>×</button>
                    </div>
                  ))}
                  <div style={{ textAlign:'right', fontWeight:700, marginTop:10, fontSize:15, fontFamily:'var(--font-mono)' }}>
                    Total: ₹{total.toLocaleString('en-IN', { minimumFractionDigits:2 })}
                  </div>
                </div>

                <button type="submit" className="btn btn-primary" disabled={loading} style={{ minWidth:180 }}>
                  {loading ? <><span className="spinner" style={{ marginRight:6 }} />Generating…</> : '⚡ Generate Challan'}
                </button>
              </form>
            )}
          </div>
          <div>
            <h3 style={{ fontSize:13, fontWeight:700, marginBottom:10, textTransform:'uppercase', letterSpacing:'0.05em', color:'var(--muted)' }}>Recent</h3>
            <RecentMini />
          </div>
        </div>
      )}

      {/* ── ALL RECORDS ── */}
      {activeTab === 'records' && (
        <div>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>
            <h2 className="page-title" style={{ margin:0 }}>
              Challan Records
              <span style={{ fontFamily:'var(--font-mono)', fontSize:13, fontWeight:400, color:'var(--muted)', marginLeft:10 }}>{recordsCount} total</span>
            </h2>
            <button className="btn btn-secondary btn-sm" onClick={loadRecords}>↻ Refresh</button>
          </div>
          <div style={{ display:'flex', gap:10, marginBottom:14, flexWrap:'wrap' }}>
            <input value={recSearch} onChange={e => setRecSearch(e.target.value)} placeholder="Search challan, customer, CCID…" style={{ maxWidth:260 }} />
            <select value={recStatus} onChange={e => setRecStatus(e.target.value)} style={{ maxWidth:190 }}>
              <option value="">All statuses</option>
              <option value="awaiting_delivery">Awaiting Delivery</option>
              <option value="rtc">Released to Customer</option>
              <option value="cancelled">Cancelled</option>
            </select>
            <select value={recMonth} onChange={e => setRecMonth(e.target.value)} style={{ maxWidth:110 }}>
              <option value="">All months</option>
              {MONTHS.map((m,i) => <option key={i} value={i+1}>{m}</option>)}
            </select>
            <select value={recYear} onChange={e => setRecYear(e.target.value)} style={{ maxWidth:90 }}>
              {years.map(y => <option key={y} value={y}>{y}</option>)}
            </select>
          </div>
          <div style={{ display:'flex', gap:14, marginBottom:12, fontSize:12, color:'var(--muted)' }}>
            <span style={{ background:'#fff8e1', padding:'2px 8px', border:'1px solid #ffe082' }}>⚠️ 3+ days awaiting</span>
            <span><span className="badge badge-committed">Awaiting Delivery</span></span>
            <span><span className="badge badge-confirmed">Released to Customer</span></span>
            <span><span className="badge badge-cancelled">Cancelled</span></span>
          </div>
          <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:10, padding:'6px 10px', background:'#f5f5f2', border:'1px solid var(--border)', borderRadius:2, fontSize:12 }}>
            <input type="checkbox" id="showInternalChk" checked={showInternal} onChange={e=>setShowInternal(e.target.checked)} style={{ width:'auto' }} />
            <label htmlFor="showInternalChk" style={{ margin:0, cursor:'pointer', color:'var(--muted)' }}>
              Show internal transfer challans
            </label>
          </div>
          <RecordsTable rows={records} user={user} onAction={handleLifecycleAction} loading={recLoading} />
        </div>
      )}

      {/* ── UNBILLED ── */}
      {activeTab === 'unbilled' && (
        <div>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>
            <h2 className="page-title" style={{ margin:0 }}>
              Unbilled Challans
              <span style={{ fontFamily:'var(--font-mono)', fontSize:13, fontWeight:400, color:'var(--warn)', marginLeft:10 }}>{unbilled.length} pending</span>
            </h2>
            <button className="btn btn-secondary btn-sm" onClick={loadUnbilled}>↻ Refresh</button>
          </div>
          <UnbilledTable rows={unbilled} onAddInvoice={handleAddInvoice} loading={unbilledLoad} />
        </div>
      )}
    </div>
  );
}
